from sqlalchemy import true
from typing import Optional
from app.domain.models.tool_result import ToolResult
from pydantic import BaseModel


class Browser(BaseModel):
    """浏览器服务扩展，涵盖：访问页面、URL跳转、输入框填充、移动鼠标、截图等操作"""

    async def view_page(self) -> ToolResult: ...
    async def navigate(self, url: str) -> ToolResult: ...
    async def restart(self, url: str) -> ToolResult: ...
    async def click(
        self,
        index: Optional[int] = None,
        coordinate_x: Optional[float] = None,
        coordinate_y: Optional[float] = None,
    ) -> ToolResult: ...
    async def input(
        self,
        text: str,
        press_enter: bool = False,
        index: Optional[int] = None,
        coordinate_x: Optional[float] = None,
        coordinate_y: Optional[float] = None,
    ) -> ToolResult: ...
    async def move_mouse(
        self,
        coordinate_x: Optional[float] = None,
        coordinate_y: Optional[float] = None,
    ) -> ToolResult: ...
    async def press_key(
        self,
        key: str,
    ) -> ToolResult: ...
    async def select_option(self, index: int, option: int) -> ToolResult: ...
    async def scroll_up(self, to_up: Optional[bool] = None) -> ToolResult: ...
    async def scroll_down(self, to_down: Optional[bool] = None) -> ToolResult: ...
    async def screen_shot(self, fuill_page: Optional[bool] = None) -> ToolResult: ...
    async def console_exec(self, javascript: str) -> ToolResult: ...
    async def console_view(self, max_lines: Optional[int] = None) -> ToolResult: ...
